class SamePlaceModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.decide = dspy.Predict(
            "input_name: str, input_address: str, match_name: str, match_address: str, distance: float -> is_same: bool"
        )

    def forward(self, **inputs):
        import re

        def normalize_name(s):
            s = (s or "").lower()
            s = s.replace("'", "").replace("`", "").replace("’", "")
            s = re.sub(r"[^a-z0-9]+", " ", s)
            stopwords = {
                "restaurant", "restaurants", "cafe", "coffee", "shop", "store",
                "inc", "llc", "co", "corp", "corporation", "company", "the",
                "and", "of", "a", "an", "food", "foods", "kitchen", "grill",
                "bar", "bakery", "market", "deli", "chinese", "mexican",
                "italian", "japanese", "thai", "indian", "american",
            }
            tokens = [t for t in s.split() if t and t not in stopwords]
            return " ".join(tokens)

        def name_core_tokens(s):
            # tokens before stopword removal (for strict comparisons)
            s = (s or "").lower()
            s = s.replace("'", "").replace("`", "").replace("’", "")
            s = re.sub(r"[^a-z0-9]+", " ", s)
            return [t for t in s.split() if t]

        def normalize_address(s):
            s = (s or "").lower()
            s = re.sub(r"[^a-z0-9]+", " ", s)
            abbrevs = {
                "street": "st", "avenue": "ave", "boulevard": "blvd",
                "road": "rd", "drive": "dr", "lane": "ln", "court": "ct",
                "place": "pl", "parkway": "pkwy", "highway": "hwy",
                "north": "n", "south": "s", "east": "e", "west": "w",
                "northeast": "ne", "northwest": "nw", "southeast": "se",
                "southwest": "sw", "suite": "ste", "apartment": "apt",
                "floor": "fl", "building": "bldg",
            }
            tokens = [abbrevs.get(t, t) for t in s.split() if t]
            return " ".join(tokens)

        def address_core(s):
            # drop trailing unit designators to compare the base address
            toks = s.split()
            unit_markers = {"ste", "apt", "unit", "fl", "bldg", "rm", "room", "no"}
            out = []
            i = 0
            while i < len(toks):
                if toks[i] in unit_markers:
                    i += 2  # skip marker and its value
                    continue
                out.append(toks[i])
                i += 1
            # also drop a single trailing letter (like "A" in "4001 PIEDMONT AVE A")
            if len(out) >= 2 and len(out[-1]) == 1 and out[-1].isalpha():
                out = out[:-1]
            return " ".join(out)

        def extract_street_number(addr):
            m = re.match(r"\s*(\d+)", addr or "")
            return m.group(1) if m else None

        def token_set(s):
            return set(s.split()) if s else set()

        def jaccard(a, b):
            if not a and not b:
                return 1.0
            if not a or not b:
                return 0.0
            return len(a & b) / len(a | b)

        def edit_ratio(a, b):
            if a == b:
                return 1.0
            if not a or not b:
                return 0.0
            la, lb = len(a), len(b)
            prev = list(range(lb + 1))
            for i in range(1, la + 1):
                curr = [i] + [0] * lb
                for j in range(1, lb + 1):
                    cost = 0 if a[i - 1] == b[j - 1] else 1
                    curr[j] = min(
                        curr[j - 1] + 1,
                        prev[j] + 1,
                        prev[j - 1] + cost,
                    )
                prev = curr
            dist = prev[lb]
            return 1.0 - dist / max(la, lb)

        in_name = inputs.get("input_name", "") or ""
        in_addr = inputs.get("input_address", "") or ""
        m_name = inputs.get("match_name", "") or ""
        m_addr = inputs.get("match_address", "") or ""
        try:
            dist = float(inputs.get("distance", 0.0))
        except (TypeError, ValueError):
            dist = 0.0

        n1 = normalize_name(in_name)
        n2 = normalize_name(m_name)
        a1 = normalize_address(in_addr)
        a2 = normalize_address(m_addr)
        a1c = address_core(a1)
        a2c = address_core(a2)

        num1 = extract_street_number(a1)
        num2 = extract_street_number(a2)

        name_edit = edit_ratio(n1, n2)
        name_jac = jaccard(token_set(n1), token_set(n2))
        addr_edit = max(edit_ratio(a1, a2), edit_ratio(a1c, a2c))
        addr_jac = max(jaccard(token_set(a1), token_set(a2)),
                       jaccard(token_set(a1c), token_set(a2c)))

        name_sim = max(name_edit, name_jac)
        addr_sim = max(addr_edit, addr_jac)

        raw_n1 = name_core_tokens(in_name)
        raw_n2 = name_core_tokens(m_name)
        raw_name_jac = jaccard(set(raw_n1), set(raw_n2))

        # ---- Deterministic decision rules (aim to answer without LLM) ----

        # 1) Far apart => definitely not the same.
        if dist > 300:
            return dspy.Prediction(is_same=False)

        # 2) Different street numbers on the same street segment => different places.
        #    (Very close distances can still be different storefronts.)
        if num1 and num2 and num1 != num2:
            # If the numbers differ by a small amount AND names are essentially identical
            # AND distance is tiny, could still be same building with unit variance.
            try:
                n_diff = abs(int(num1) - int(num2))
            except ValueError:
                n_diff = 999
            if not (n_diff <= 4 and name_sim >= 0.9 and dist < 30):
                return dspy.Prediction(is_same=False)

        # 3) Same (or missing) street number + very similar address + similar name + close.
        street_nums_ok = (num1 is None or num2 is None or num1 == num2)
        if street_nums_ok and addr_sim >= 0.85 and name_sim >= 0.7 and dist < 100:
            return dspy.Prediction(is_same=True)

        # 4) Identical normalized name AND same street number AND close.
        if n1 and n1 == n2 and street_nums_ok and dist < 150:
            return dspy.Prediction(is_same=True)

        # 5) Identical raw-name tokens (names match exactly ignoring case/punct) and close.
        if raw_n1 and raw_n1 == raw_n2 and street_nums_ok and dist < 100:
            return dspy.Prediction(is_same=True)

        # 6) Strong name match + same base address.
        if a1c and a1c == a2c and name_sim >= 0.6 and dist < 100:
            return dspy.Prediction(is_same=True)

        # 7) Both name and address clearly different => not same.
        if name_sim < 0.5 and addr_sim < 0.6:
            return dspy.Prediction(is_same=False)

        # 8) Same street number, close, but very different names => different businesses
        #    at same address (co-tenants).
        if street_nums_ok and dist < 50 and raw_name_jac < 0.2 and name_sim < 0.4:
            return dspy.Prediction(is_same=False)

        # 9) Moderately far with weak similarity.
        if dist > 150 and (name_sim < 0.7 or addr_sim < 0.7):
            return dspy.Prediction(is_same=False)

        # Ambiguous — fall back to LLM.
        result = self.decide(
            input_name=in_name,
            input_address=in_addr,
            match_name=m_name,
            match_address=m_addr,
            distance=dist,
        )
        val = result.is_same
        if isinstance(val, str):
            val = val.strip().lower() in ("true", "1", "yes", "y")
        return dspy.Prediction(is_same=bool(val))
